		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	result := v.client.B().Zadd().Key(LastActivityIndexKey).MemberScore().Member(sessionID).Score(float64(at.Unix())).Build()
	err = v.client.Do(ctx, result).Error()
	if err != nil {
		return err
	}

	klog.V(4).Infof("Updated last activity for session %s", sessionID)
	return nil
}

func (v *ValkeyStore) Close() {
	if v.client != nil {
		v.client.Close()
	}
}

