package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type ValkeyStore struct {
	client valkey.Client
}

func NewValkeyStore() (*ValkeyStore, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		return nil, errors.New("VALKEY_ADDR environment variable is not set")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("VALKEY_PASSWORD_REQUIRED"); val != "" {
		passwordRequired = strings.ToLower(val) != "false"
	}

	if password == "" && passwordRequired {
		return nil, errors.New("VALKEY_PASSWORD is required (set VALKEY_PASSWORD_REQUIRED=false to disable)")
	}

	disableCache := false
	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		disableCache = strings.ToLower(val) == "true"
	}

	forceSingleClient := false
	if val := os.Getenv("VALKEY_FORCE_SINGLE"); val != "" {
		forceSingleClient = strings.ToLower(val) == "true"
	}

	initAddresses := strings.Split(addr, ",")
	for i, a := range initAddresses {
		initAddresses[i] = strings.TrimSpace(a)
	}

	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress:       initAddresses,
		Password:          password,
		DisableCache:      disableCache,
		ForceSingleClient: forceSingleClient,
	})
	if err != nil {
		return nil, err
	}

	return &ValkeyStore{
		client: client,
	}, nil
}

func (v *ValkeyStore) Ping(ctx context.Context) error {
	result := v.client.B().Ping().Build()
	resp, err := v.client.Do(ctx, result).ToString()
	if err != nil {
		return err
	}
	if resp != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", resp)
	}
	return nil
}

func (v *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := sessionKey(sessionID)
	result := v.client.B().Get().Key(key).Build()
	resp := v.client.Do(ctx, result)

	data, err := resp.AsBytes()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (v *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("sandbox expiresAt cannot be zero")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	dedicatedClient, cancel := v.client.Dedicate()
	defer cancel()

	setnxResult := dedicatedClient.Do(ctx, dedicatedClient.B().Set().Key(key).Value(string(data)).Nx().Build())
	setnxVal, err := setnxResult.AsInt64()
	if err != nil {
		return err
	}
	if setnxVal == 0 {
		return errors.New("session already exists")
	}

	expiryResult := dedicatedClient.Do(ctx, dedicatedClient.B().Zadd().Key(ExpiryIndexKey).MemberScore().Member(sandbox.SessionID).Score(float64(sandbox.ExpiresAt.Unix())).Build())
	if err := expiryResult.Error(); err != nil {
		return err
	}

	activityResult := dedicatedClient.Do(ctx, dedicatedClient.B().Zadd().Key(LastActivityIndexKey).MemberScore().Member(sandbox.SessionID).Score(float64(time.Now().Unix())).Build())
	if err := activityResult.Error(); err != nil {
		return err
	}

	klog.V(4).Infof("Stored sandbox for session %s", sandbox.SessionID)
	return nil
}

func (v *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	result := v.client.B().Set().Key(key).Value(string(data)).Xx().Build()
	resp := v.client.Do(ctx, result)

	ok, err := resp.AsBool()
	if err != nil {
		return err
	}
	if !ok {
		return errors.New("key not exists")
	}

	klog.V(4).Infof("Updated sandbox for session %s", sandbox.SessionID)
	return nil
}

func (v *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)

	dedicatedClient, cancel := v.client.Dedicate()
	defer cancel()

	delResult := dedicatedClient.Do(ctx, dedicatedClient.B().Del().Key(key).Build())
	delCount, err := delResult.AsInt64()
	if err != nil {
		return err
	}
	if delCount == 0 {
		return ErrNotFound
	}

	zremExpiry := dedicatedClient.Do(ctx, dedicatedClient.B().Zrem().Key(ExpiryIndexKey).Member(sessionID).Build())
	if err := zremExpiry.Error(); err != nil {
		return err
	}

	zremActivity := dedicatedClient.Do(ctx, dedicatedClient.B().Zrem().Key(LastActivityIndexKey).Member(sessionID).Build())
	if err := zremActivity.Error(); err != nil {
		return err
	}

	klog.V(4).Infof("Deleted sandbox for session %s", sessionID)
	return nil
}

func (v *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	result := v.client.B().Zrange().Key(ExpiryIndexKey).Score().Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, int64(limit)).Build()
	resp, err := v.client.Do(ctx, result).AsStrSlice()
	if err != nil {
		return nil, err
	}

	sessionIDs := make([]string, len(resp))
	copy(sessionIDs, resp)

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	result := v.client.B().Zrange().Key(LastActivityIndexKey).Score().Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, int64(limit)).Build()
	resp, err := v.client.Do(ctx, result).AsStrSlice()
	if err != nil {
		return nil, err
	}

	sessionIDs := make([]string, len(resp))
	copy(sessionIDs, resp)

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *ValkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, sid := range sessionIDs {
		keys[i] = sessionKey(sid)
	}

	result := v.client.B().Mget().Key(keys...).Build()
	resp, err := v.client.Do(ctx, result).AsStrSlice()
	if err != nil {
		return nil, err
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(sessionIDs))
	for i, data := range resp {
		if data == "" {
			klog.V(4).Infof("Skipping orphan session ID: %s", sessionIDs[i])
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			klog.V(4).Infof("Skipping unmarshalable data for session ID: %s", sessionIDs[i])
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

func (v *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID cannot be empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKey(sessionID)
	existsResult := v.client.B().Exists().Key(key).Build()
	exists, err := v.client.Do(ctx, existsResult).AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	result := v.client.B().Zadd().Key(LastActivityIndexKey).Score().Member(sessionID).Score(float64(at.Unix())).Build()
	err = v.client.Do(ctx, result).Error()
	if err != nil {
		return err
	}

	klog.V(4).Infof("Updated last activity for session %s", sessionID)
	return nil
}

func (v *ValkeyStore) Close() {
	if v.client != nil {
		v.client.Close()
	}
}

